metadata      <- read_tsv(meta_path, show_col_types = FALSE)

# Columns to adjust (excluding header name)
cols_to_adjust <- adjust_length[[1]]
cols_to_adjust <- cols_to_adjust[cols_to_adjust != "adjust_length"]

# Ensure classes/lengths match by coercing specified cols to character, then back if needed
for (cl in cols_to_adjust) {
  if (cl %in% names(metadata)) {
    # Standardize length via character then numeric if appropriate
    # First coerce to character to "adjust length"
    metadata[[cl]] <- as.character(metadata[[cl]])
    # If column looks numeric, coerce back to numeric
    if (all(is.na(metadata[[cl]]) | str_detect(metadata[[cl]], "^[-+]?[0-9]*\\.?[0-9]+$"))) {
      metadata[[cl]] <- as.numeric(metadata[[cl]])
    }
  }
}

# Build and evaluate expression(s) from df.tsv
# Expecting something like: set_values_to / exprs(AVAL = mean(AVAL, na.rm=TRUE))
expr_line <- df_spec$set_values_to[1]
expr_line <- str_trim(expr_line)

# Evaluate within metadata environment
expr_obj <- eval(parse(text = expr_line), envir = as.list(metadata))

