if (is.list(expr_obj)) {
  for (nm in names(expr_obj)) {
    if (length(expr_obj[[nm]]) == 1L) {
      metadata[[nm]] <- expr_obj[[nm]]
    } else if (length(expr_obj[[nm]]) == nrow(metadata)) {
      metadata[[nm]] <- expr_obj[[nm]]
    } else {
      metadata[[nm]] <- rep(expr_obj[[nm]], length.out = nrow(metadata))
    }
  }
}

# Write result
out_path <- file.path(out_dir, "result.csv")
write_csv(metadata, out_path)
