longest_common_prefix <- function(x) {
  if (length(x) == 0) return("")
  if (length(x) == 1) return(x)

  # Split into characters
  split_chars <- str_split(x, "", simplify = FALSE)
  min_len <- min(lengths(split_chars))

  prefix_chars <- character(0)
  for (i in seq_len(min_len)) {
    current_chars <- vapply(split_chars, `[[`, character(1), i)
    if (length(unique(current_chars)) == 1) {
      prefix_chars <- c(prefix_chars, current_chars[1])
    } else {
      break
    }
  }
  paste(prefix_chars, collapse = "")
}

common_prefix <- longest_common_prefix(strings)

# Prepare result
result <- tibble(
  common_prefix = common_prefix
)

# Ensure outputs directory exists
