  is.numeric(x) &&
    all(is.na(x) | (floor(x) == x))
}

# Apply formatting
dat_fmt <- dat

for (v in vars_to_format) {
  if (!v %in% names(dat_fmt)) next
  col <- dat_fmt[[v]]
  if (is.numeric(col)) {
    if (is_integer_like(col)) {
      dat_fmt[[v]] <- sprintf("%d", as.integer(round(col)))
    } else {
      # format to 2 decimal places, trim trailing zeros and decimal
      tmp <- sprintf("%.2f", col)
      tmp[is.na(col)] <- NA_character_
      tmp <- str_replace(tmp, "0+$", "")
      tmp <- str_replace(tmp, "[.]$", "")
      dat_fmt[[v]] <- tmp
    }
  } else {
    dat_fmt[[v]] <- col
  }
}

# Write result
write_csv(dat_fmt, out_path, na = "")
