# Input/output paths
in_imputed <- file.path("inputs", "imputed_dtc.tsv")
in_partial <- file.path("inputs", "partial.tsv")
out_file   <- file.path("outputs", "result.csv")

# Read inputs
imputed_dtc <- read_tsv(in_imputed, show_col_types = FALSE)
partial     <- read_tsv(in_partial, show_col_types = FALSE)

# Helper: parse partial DTC per ADaM last-day imputation rules
parse_partial_dtc <- function(x) {
  x <- str_trim(x)
  if (x == "" | is.na(x)) return(NA_character_)

  # Full date (YYYY-MM-DD or ISO with time)
  if (str_detect(x, "^\\d{4}-\\d{2}-\\d{2}")) {
    dt <- as.Date(substr(x, 1, 10))
    return(format(dt, "%Y-%m-%d"))
  }

  # Year only YYYY -> last day of year
  if (str_detect(x, "^\\d{4}$")) {
    yr <- as.integer(substr(x, 1, 4))
    dt <- as.Date(paste0(yr, "-12-31"))
    return(format(dt, "%Y-%m-%d"))
  }

  # Year-month YYYY-MM -> last day of that month
  if (str_detect(x, "^\\d{4}-\\d{2}$")) {
    yr  <- as.integer(substr(x, 1, 4))
    mon <- as.integer(substr(x, 6, 7))
    # first day of next month minus one day
    if (mon == 12) {
      dt_next <- as.Date(paste0(yr + 1, "-01-01"))
    } else {
      dt_next <- as.Date(sprintf("%04d-%02d-01", yr, mon + 1))
    }
    dt <- dt_next - 1
    return(format(dt, "%Y-%m-%d"))
  }

  # Anything else not handled -> NA
  return(NA_character_)
}

# Apply imputation to imputed_dtc$dtc:
# - If full date present, keep as is
# - If partial (missing day or month/day), impute last day
# - Preserve any time part
impute_last_day <- function(x) {
  x <- str_trim(x)
  if (x == "" | is.na(x)) return(NA_character_)

  # Split date and time (if present)
  # Assume ISO-like forms: date part up to first "T"
  parts <- str_split_fixed(x, "T", 2)
  date_part <- parts[, 1]
  time_part <- ifelse(parts[, 2] == "", NA_character_, parts[, 2])

  # If full date (YYYY-MM-DD)
  if (str_detect(date_part, "^\\d{4}-\\d{2}-\\d{2}$")) {
    base_date <- date_part
  } else {
    # Year-only or year-month or other partials
    base_date <- parse_partial_dtc(date_part)
  }

  if (is.na(base_date)) return(NA_character_)

  if (!is.na(time_part)) {
    return(paste0(base_date, "T", time_part))
  } else {
    return(base_date)
  }
}

imputed_dtc <- imputed_dtc %>%
  mutate(
    imputed = vapply(dtc, impute_last_day, character(1))
  )

partial <- partial %>%
  mutate(
    imputed = vapply(partial, parse_partial_dtc, character(1))
  )

# Combine into one result table
result <- bind_rows(
  imputed_dtc %>% mutate(source = "imputed_dtc") %>% rename(input = dtc),
  partial     %>% mutate(source = "partial")     %>% rename(input = partial)
) %>%
  select(source, input, imputed)

# Ensure outputs directory exists
if (!dir.exists("outputs")) dir.create("outputs", recursive = TRUE)

# Write result
write_csv(result, out_file)
