library(readr)
library(dplyr)
library(lubridate)
library(stringr)
library(purrr)

#---------------------------
# Helpers
#---------------------------

read_single_col <- function(path) {
  x <- read_tsv(path, show_col_types = FALSE, col_types = cols(.default = "c"))[[1]]
  x[!is.na(x) & x != ""]
}

#---------------------------
# Read inputs
#---------------------------

add_one    <- read_single_col("inputs/add_one.tsv")
end_date   <- read_single_col("inputs/end_date.tsv")[-1]
floor_in   <- read_single_col("inputs/floor_in.tsv")
in_unit    <- read_single_col("inputs/in_unit.tsv")[1]
out_unit   <- read_single_col("inputs/out_unit.tsv")[1]
start_date <- read_single_col("inputs/start_date.tsv")[-1]
trunc_out  <- read_single_col("inputs/trunc_out.tsv")
type_val   <- read_single_col("inputs/type.tsv")[1]

#---------------------------
# Base data construction
#---------------------------

n <- min(length(start_date), length(end_date))
start_date <- start_date[seq_len(n)]
end_date   <- end_date[seq_len(n)]

df <- tibble(
  USUBJID = paste0("SUBJ", seq_len(n)),
  AVISITN = seq_len(n),
  STARTDT = ymd(start_date),
  ENDDT   = ymd(end_date)
)

#---------------------------
# Duration computation
#---------------------------

if (!identical(type_val, "interval")) {
  stop("Only 'interval' type supported in this script.")
}

# compute raw duration in input unit
if (identical(in_unit, "days")) {
  df <- df %>%
    mutate(AVAL = as.numeric(ENDDT - STARTDT))
} else if (identical(in_unit, "weeks")) {
  df <- df %>%
    mutate(AVAL = as.numeric(ENDDT - STARTDT) / 7)
} else if (identical(in_unit, "months")) {
  df <- df %>%
    mutate(AVAL = time_length(interval(STARTDT, ENDDT), "months"))
} else if (identical(in_unit, "years")) {
  df <- df %>%
    mutate(AVAL = time_length(interval(STARTDT, ENDDT), "years"))
} else {
  stop("Unsupported in_unit")
}

# floor_in: floor for specified variables
if ("AVAL" %in% floor_in) {
  df <- df %>% mutate(AVAL = floor(AVAL))
}

# convert to output unit
conv_fun <- function(x, in_u, out_u) {
  if (in_u == out_u) return(x)
  if (in_u == "days"   && out_u == "years") return(x / 365.25)
  if (in_u == "days"   && out_u == "weeks") return(x / 7)
  if (in_u == "weeks"  && out_u == "days")  return(x * 7)
  if (in_u == "weeks"  && out_u == "years") return(x * 7 / 365.25)
  if (in_u == "months" && out_u == "years") return(x / 12)
  if (in_u == "years"  && out_u == "days")  return(x * 365.25)
  if (in_u == "years"  && out_u == "weeks") return(x * 365.25 / 7)
  if (in_u == "years"  && out_u == "months")return(x * 12)
  if (in_u == "months" && out_u == "days")  return(x * 30.4375)
  if (in_u == "months" && out_u == "weeks") return(x * 30.4375 / 7)
  stop("Unsupported conversion")
}

df <- df %>%
