# trunc_out: truncate after conversion for specified variables
if ("AVAL" %in% trunc_out) {
  df <- df %>% mutate(AVAL = floor(AVAL))
}

# add_one: add 1 to specified variables
if ("AVAL" %in% add_one) {
  df <- df %>% mutate(AVAL = AVAL + 1)
}

#---------------------------
# Output
#---------------------------

result <- df %>%
