  mutate(
    ADT = ymd(ADT)
  ) %>%
  group_by(USUBJID) %>%
  slice(1) %>%
  ungroup() %>%
  select(USUBJID, STUDYID, ADT)

# Match lengths of date vectors to subjects
n_subj <- nrow(adsl_like)

rep_vector <- function(x, n) {
  if (length(x) == 0) return(rep(NA, n))
  rep(x, length.out = n)
}

adsl_dates <- adsl_like %>%
  mutate(
    STARTDT_SRC  = rep_vector(start_date$start_date, n_subj),
    ENDDT_SRC    = rep_vector(end_date$end_date, n_subj),
    STARTDT_DF   = rep_vector(start_date_df$start_date, n_subj),
    ENDDT_DF     = rep_vector(end_date_df$end_date, n_subj)
  )

# Derive AAGE using admiral::derive_vars_aage-like logic
