# Helper to detect DTC precision
dtc_precision <- function(x) {
  if (is.na(x) || x == "") return(NA_character_)
  if (str_detect(x, "^\\d{4}-\\d{2}-\\d{2}$")) return("D")
  if (str_detect(x, "^\\d{4}-\\d{2}$")) return("M")
  if (str_detect(x, "^\\d{4}$")) return("Y")
  NA_character_
}

# Imputation rules
impute_dtc <- function(dtc,
                       date_imputation = c("NONE","FIRST","MID","LAST"),
                       highest_imputation = c("Y","M","D"),
                       min_date = NA_Date_,
                       max_date = NA_Date_) {
  date_imputation <- match.arg(date_imputation)
  highest_imputation <- match.arg(highest_imputation)

  prec <- dtc_precision(dtc)

  if (is.na(dtc) || dtc == "" || is.na(prec)) return(NA_character_)

  # If precision already at or higher than allowed highest, keep as is
  if ((highest_imputation == "Y" && prec %in% c("Y","M","D")) ||
      (highest_imputation == "M" && prec %in% c("M","D")) ||
      (highest_imputation == "D" && prec == "D")) {
    return(dtc)
  }

  # Decide day/month to use
