  pull(1)

preserve_cols <- read_tsv(file.path(in_path, "preserve.tsv"), show_col_types = FALSE) |>
  pull(1)

# Helper to detect DTC precision
dtc_precision <- function(x) {
  if (is.na(x) || x == "") return(NA_character_)
  if (str_detect(x, "^\\d{4}-\\d{2}-\\d{2}$")) return("D")
  if (str_detect(x, "^\\d{4}-\\d{2}$")) return("M")
  if (str_detect(x, "^\\d{4}$")) return("Y")
  NA_character_
}

# Imputation rules
impute_dtc <- function(dtc,
                       date_imputation = c("NONE","FIRST","MID","LAST"),
                       highest_imputation = c("Y","M","D"),
                       min_date = NA_Date_,
                       max_date = NA_Date_) {
  date_imputation <- match.arg(date_imputation)
  highest_imputation <- match.arg(highest_imputation)

  prec <- dtc_precision(dtc)

  if (is.na(dtc) || dtc == "" || is.na(prec)) return(NA_character_)

  # If precision already at or higher than allowed highest, keep as is
  if ((highest_imputation == "Y" && prec %in% c("Y","M","D")) ||
      (highest_imputation == "M" && prec %in% c("M","D")) ||
      (highest_imputation == "D" && prec == "D")) {
    return(dtc)
  }

  # Decide day/month to use
  get_day <- function(year, month) {
    if (date_imputation == "FIRST") return(1L)
    if (date_imputation == "LAST") {
      return(lubridate::days_in_month(as.Date(sprintf("%04d-%02d-01", year, month))))
    }
    # MID
    as.integer(round(lubridate::days_in_month(as.Date(sprintf("%04d-%02d-01", year, month))) / 2))
  }

  get_month <- function() {
    if (date_imputation == "FIRST") return(1L)
    if (date_imputation == "LAST") return(12L)
    6L
  }

  # Build full date string
  if (prec == "Y") {
    year <- as.integer(substr(dtc, 1, 4))
    if (highest_imputation == "Y") return(dtc)

    month <- get_month()
    if (highest_imputation == "M") {
      return(sprintf("%04d-%02d", year, month))
    }

    day <- get_day(year, month)
    full <- as.Date(sprintf("%04d-%02d-%02d", year, month, day))
  } else if (prec == "M") {
    year  <- as.integer(substr(dtc, 1, 4))
    month <- as.integer(substr(dtc, 6, 7))
    if (highest_imputation == "M") return(dtc)

    day  <- get_day(year, month)
    full <- as.Date(sprintf("%04d-%02d-%02d", year, month, day))
  } else {
    # already full date
    full <- as.Date(dtc)
  }

  # Apply min / max bounds if provided
  if (!is.na(min_date) && full < min_date) full <- min_date
  if (!is.na(max_date) && full > max_date) full <- max_date

  format(full, "%Y-%m-%d")
}

# Prepare max_dates vector (coerce DTC-like to Date, others NA)
max_dates <- max_dates_raw |>
  mutate(
    idx = row_number(),
    dt  = suppressWarnings(as.Date(dtc))
  ) |>
  pull(dt)

# Align lengths
n <- nrow(dtc_df)
if (length(max_dates) < n) {
  max_dates <- c(max_dates, rep(NA, n - length(max_dates)))
} else if (length(max_dates) > n) {
  max_dates <- max_dates[seq_len(n)]
}

# For this task, min_date not used (no pairing info); set to NA
min_dates_vec <- rep(as.Date(NA), n)

dtc_df <- dtc_df |>
  mutate(
    imputed = pmap_chr(
      list(
        dtc,
        min_dates_vec,
        max_dates
      ),
      ~ impute_dtc(..1,
                   date_imputation = date_imputation[1],
                   highest_imputation = highest_imputation[1],
                   min_date = ..2,
                   max_date = ..3)
    )
  )

