# Propagate NA per admiral clinical task contract ------------------------
# Rule:
# - Identify the first non-missing value
# - Forward-fill down the column until another non-missing value occurs
# - Each new non-missing value becomes the new "source" to propagate
# - Missing values above the first non-missing remain as is

partial_vec <- dat$partial

# Forward fill: base R implementation
fill_forward <- function(x) {
  out <- x
  last_val <- NA_character_
  for (i in seq_along(x)) {
    if (!is.na(x[i]) && nzchar(x[i])) {
      last_val <- x[i]
      out[i] <- x[i]
    } else {
      out[i] <- last_val
    }
  }
  # Ensure leading values before first non-missing stay as original
  first_non_na <- which(!is.na(x) & nzchar(x))[1]
  if (!is.na(first_non_na) && first_non_na > 1) {
    out[seq_len(first_non_na - 1)] <- x[seq_len(first_non_na - 1)]
  }
  out
}

result_vec <- fill_forward(partial_vec)

result <- tibble(partial = result_vec)

# Write output ------------------------------------------------------------
write_csv(result, out_file, na = "")
