#!/usr/bin/env Rscript

library(dplyr)
library(readr)
library(stringr)
library(tools)

# Create outputs directory if it does not exist
if (!dir.exists("outputs")) dir.create("outputs", recursive = TRUE)

# Read input
infile <- file.path("inputs", "data.tsv")

dat <- read_tsv(
  infile,
  col_types = cols(.default = col_character())
)

# Remove labels according to metatools "remove labels" concept:
# - Convert all variable names to upper case
# - Remove non-alphanumeric characters from names
# - Trim whitespace in character data
# - Coerce numeric-like columns to numeric where appropriate

# Standardize column names
names(dat) <- names(dat) |>
  toupper() |>
  str_replace_all("[^A-Z0-9_]", "_")

# Trim character columns
dat <- dat %>%
  mutate(across(where(is.character), ~ str_trim(.x)))

# Try to convert numeric-like columns
make_numeric_if_possible <- function(x) {
  suppressWarnings({
    xn <- as.numeric(x)
  })
  if (all(is.na(xn) == is.na(x))) {
    return(xn)
  } else {
    return(x)
  }
}

dat <- dat %>%
  mutate(across(everything(), make_numeric_if_possible))

# Write output
outfile <- file.path("outputs", "result.csv")
write_csv(dat, outfile, na = "")

